// 生成模拟数据
const faker = require('faker')
let users = [];
for (let i = 0; i < 10; i++) {
    users.push({
        id: i + 1,
        name: faker.name.findName(undefined, undefined, undefined),
        email: faker.internet.email(),
        mobile: faker.phone.phoneNumber(undefined)
    });
}
export const list = params => new Promise(resolve => {
    setTimeout(() => {
        resolve({
            total: 100,
            records: users.filter(e => {
                if (params.name)
                    return e.name.toLowerCase().indexOf(params.name.toLowerCase()) >= 0;
                return true;
            })
        });
    }, 500);
}); // 模拟接口请求
