<template>
    <div>
        <el-form inline>
            <el-form-item label="姓名">
                <el-input v-model="form.name" clearable></el-input>
            </el-form-item>
            <el-form-item label=" ">
                <el-button icon="el-icon-refresh" @click="reset">重置</el-button>
                <el-button icon="el-icon-plus" type="primary">创建</el-button>
            </el-form-item>
        </el-form>
        <el-table ref="table" :data="records" border v-loading="loading" @sort-change="sort" :row-class-name="e=>e.row.id!==currentRow||'current-row'">
            <el-table-column prop="id" label="ID" sortable="custom" width="100"></el-table-column>
            <el-table-column prop="name" label="姓名" sortable="custom" width="400"></el-table-column>
            <el-table-column prop="email" label="邮箱" sortable="custom" width="400"></el-table-column>
            <el-table-column prop="mobile" label="联系方式" sortable="custom" width="400"></el-table-column>
            <el-table-column label="操作" fixed="right" width="100" align="center">
                <template slot-scope="{row}">
                    <el-button class="p-0" type="text" size="large" icon="el-icon-info" @click="detail(row.id)"></el-button>
                    <el-button class="p-0" type="text" size="large" icon="el-icon-edit" @click="edit(row.id)"></el-button>
                    <el-button class="p-0 text-danger" type="text" size="large" icon="el-icon-delete" @click="drop(row.id)"></el-button>
                </template>
            </el-table-column>
        </el-table>
        <pagination v-model="form" :total="total"/>
        <small>faker.js模拟数据</small>

        <detail ref="detail"/>
    </div>
</template>
<script>
    import {list} from "@/plugins/axios/api/user";
    import Pagination from "@/components/util/Pagination";
    import Detail from "@/pages/index/Detail";

    export default {
        components: {Detail, Pagination},
        data() {
            return {
                form: {}, // 查询表单
                loading: false,
                records: [], // 表格数据
                total: 0,
                currentRow: null
            }
        },
        methods: {
            list() {
                console.log("查询参数：", JSON.stringify(this.form, null, 2))
                this.loading = true;
                list(this.form).then(data => {
                    this.records = data.records;
                    this.total = data.total;
                    // 根据后台传过来的数据修正页码
                    // this.form.pageNum = data.current;
                    // this.form.pageSize = data.size;
                }).finally(() => this.loading = false);
            },
            reset() {
                this.form = {};
                this.$refs.table.clearSort(); // 清空排序状态
            },
            sort(e) {
                this.$set(this.form, 'pageOrder', e.prop);
                this.$set(this.form, 'pageAsc', e.order);
            },
            detail(id) {
                this.currentRow = id;
                this.$refs.detail.show();
            },
            edit(id) {
                this.currentRow = id;
            },
            drop(id) {
                this.currentRow = id;
            },
        },
        watch: { // 监听表单变化，触发查询
            form: {
                handler() {
                    this.list();
                },
                deep: true
            }
        },
        created() {
            this.list();
        }
    }
</script>
