<template>
    <div>
        <div v-for="(e, index) in items" :key="index">
            <el-pagination v-if="total > 0"
                           :small="mini"
                           :hide-on-single-page="mini"
                           background
                           :class="e.className"
                           :layout="mini ? 'prev, pager, next' : e.layout"
                           :total="total"
                           :current-page="data.pageNum"
                           :pager-count="e.pagerCount"
                           :page-size="data.pageSize"
                           :page-sizes="[10, 20, 50, 100]"
                           @current-change="jump"
                           @size-change="resize"
            ></el-pagination>
        </div>
    </div>
</template>
<script>
    export default {
        data() {
            return {
                items: [
                    {className: 'm-1 hidden-sm-and-down', pagerCount: 7, layout: 'total, sizes, ->, jumper, prev, pager, next'},
                    {className: 'm-1 hidden-md-and-up', pagerCount: 5, layout: 'prev, pager, next'},
                ]
            }
        },
        props: {
            data: {
                type: Object,
                required: true
            },
            total: {
                type: Number,
                required: true
            },
            mini: {
                type: Boolean,
                default: false
            }
        },
        model: {
            prop: 'data',
            event: 'a'
        },
        methods: {
            jump(e) {
                this.$emit('a', {...this.data, pageNum: e});
            },
            resize(e) {
                this.$emit('a', {...this.data, pageSize: e});
            }
        }
    }
</script>
<style scoped>
    .hidden-md-and-up.el-pagination {
        text-align: center;
    }
</style>
